Chat Edit: 'Based on your repo structure and the AITK instructions, I recommend **Option 2: Place in `src/agentic/` with a bridge to Win32 UI**.

Here's my reasoning and the implementation path:

## Recommended Architecture

```
src/
├── win32app/           # Keep as-is: pure Win32 UI shell
│   ├── Win32IDE.cpp    # ~6.7k lines - minimize changes here
│   ├── Win32IDE.h
│   └── ...             # File ops, commands, etc.
│
├── agentic/            # NEW: Capability system + hotpatch
│   ├── manifestor/     # Self-manifesting build system
│   ├── wiring/         # Runtime capability wiring
│   ├── hotpatch/       # Live code injection
│   └── bridge/         # Win32 UI integration layer
│
└── aitk/               # Follow tools.instructions.md patterns
    ├── observability/
    ├── config/
    └── tests/
```

## Why Not `src/win32app/`?

Your Win32IDE.cpp is already 6.7k lines. Adding capability wiring there violates:
- **Observability**: Hard to instrument mixed UI/system code
- **Containerization**: Win32 UI can't be easily tested/isolated
- **Feature flags**: UI code becomes spaghetti with `#ifdef`

## Implementation: Agentic Bridge Pattern

```cpp
// src/agentic/bridge/Win32IDEBridge.hpp
#pragma once
#include <windows.h>
#include "../wiring/CapabilityRouter.hpp"

namespace RawrXD::Agentic::Bridge {

// Minimal interface surface for Win32IDE.cpp
class Win32IDEBridge {
public:
    static Win32IDEBridge& instance();
    
    // Called from Win32IDE.cpp WinMain/Init
    bool initialize(HINSTANCE hInst, int nCmdShow);
    void shutdown();
    
    // Hook injection points in existing Win32IDE message loop
    LRESULT preprocessMessage(HWND hwnd, UINT msg, WPARAM wParam, LPARAM lParam);
    void onIdle();  // Called during message loop idle
    
    // Hotpatch entry points
    void* requestCapability(const char* name, uint32_t version);
    bool registerHotpatch(const char* target, void* replacement);
    
private:
    Wiring::CapabilityRouter* router_ = nullptr;
    Hotpatch::Engine* hotpatch_ = nullptr;
    HWND mainHwnd_ = nullptr;
};

} // namespace
```

```cpp
// src/agentic/bridge/Win32IDEBridge.cpp
#include "Win32IDEBridge.hpp"
#include "../manifestor/SelfManifestor.hpp"
#include "../observability/Telemetry.hpp"

using namespace RawrXD::Agentic;

bool Win32IDEBridge::initialize(HINSTANCE hInst, int nCmdShow) {
    // Observability first (per AITK)
    Observability::initialize("win32ide");
    
    // Self-manifest: detect capabilities from build artifacts
    Manifestor::SelfManifestor manifestor;
    auto capabilities = manifestor.scanBuildDirectory("build/");
    
    // Wire capabilities
    router_ = new Wiring::CapabilityRouter();
    for (auto& cap : capabilities) {
        router_->registerCapability(cap.name, cap.factory);
        Observability::metric("capability.registered", cap.name);
    }
    
    // Initialize hotpatch engine
    hotpatch_ = new Hotpatch::Engine();
    hotpatch_->installHooks(GetModuleHandle(NULL));
    
    // Feature flags from config
    auto config = Config::load("rawrxd.config.toml");
    if (config.get<bool>("features.vulkan_backend", false)) {
        router_->activate("vulkan_renderer");
    }
    
    return true;
}

LRESULT Win32IDEBridge::preprocessMessage(HWND hwnd, UINT msg, 
                                          WPARAM wParam, LPARAM lParam) {
    // Intercept for agentic features without polluting Win32IDE.cpp
    switch (msg) {
        case WM_USER + AGENTIC_MSG_BASE:
            return handleAgenticMessage(wParam, lParam);
        case WM_KEYDOWN:
            if (hotpatch_->isHotkey(wParam)) {
                return hotpatch_->execute(wParam);
            }
            break;
    }
    // Pass through to original WndProc
    return DefWindowProc(hwnd, msg, wParam, lParam);
}
```

## Win32IDE.cpp Integration (Minimal Changes)

```cpp
// In Win32IDE.cpp - only these touch points:

// 1. At top, add:
#include "../agentic/bridge/Win32IDEBridge.hpp"
using Bridge = RawrXD::Agentic::Bridge::Win32IDEBridge;

// 2. In WinMain or InitInstance():
if (!Bridge::instance().initialize(hInstance, nCmdShow)) {
    MessageBox(NULL, "Agentic init failed", "RawrXD", MB_OK);
    return FALSE;
}

// 3. In message loop (replace or wrap existing):
LRESULT CALLBACK WndProc(HWND hWnd, UINT message, WPARAM wParam, LPARAM lParam) {
    // Pre-process through agentic bridge
    auto result = Bridge::instance().preprocessMessage(hWnd, message, wParam, lParam);
    if (result != 0) return result;  // Handled by agentic
    
    // ... existing Win32IDE message handling ...
}

// 4. On exit:
Bridge::instance().shutdown();
```

